  KanjiEntry('鮃','','','',0,9999,null,'','Nature_Animal_Fish'),
];


List<List<KanjiEntry>> buildDayPlan(int perDay) {
  final days = <List<KanjiEntry>>[];
  for (int i = 0; i < allKanji.length; i += perDay) {
    final end = (i + perDay < allKanji.length) ? i + perDay : allKanji.length;
    days.add(allKanji.sublist(i, end));
  }
  return days;
}

String jlptLabel(int level) {
  if (level == 0) return 'Beyond JLPT';
  return 'JLPT N\$level';
}

String categoryIcon(String cat) {
  final c = cat.toLowerCase();
  if (c.contains('count')) return '🔢';
  if (c.contains('direct') || c.contains('movement')) return '🧭';
  if (c.contains('body') || c.contains('organ')) return '🫀';
  if (c.contains('nature') || c.contains('animal') || c.contains('plant')) return '🌿';
  if (c.contains('food') || c.contains('drink')) return '🍜';
  if (c.contains('people') || c.contains('family')) return '👥';
  if (c.contains('time')) return '⏰';
  if (c.contains('emotion')) return '💭';
  if (c.contains('human') || c.contains('communication')) return '💬';
  if (c.contains('structure') || c.contains('building')) return '🏛️';
  if (c.contains('manufactured') || c.contains('vehicle')) return '⚙️';
  if (c.contains('clothing')) return '👘';
  if (c.contains('money') || c.contains('commerce')) return '💴';
  if (c.contains('religion')) return '⛩️';
  if (c.contains('zodiac')) return '🐉';
  if (c.contains('weather') || c.contains('sky')) return '🌤️';
  if (c.contains('landscape') || c.contains('substance')) return '⛰️';
  if (c.contains('color') || c.contains('shape')) return '🎨';
  return '📖';
}
